const raw = $json;

// ============================================================
// WA_00_Webhook_Master / Code - Parse Meta Payload
// Version: 0.2.2
// Purpose:
// - Parse Meta WhatsApp webhook payload from n8n wrapper
// - Preserve legacy contract for downstream nodes
// - Add normalized fields for newer flows
// - Prioritize messages over statuses if both exist
// ============================================================

// -----------------------------
// Helpers
// -----------------------------
function firstArrayItem(value) {
  return Array.isArray(value) && value.length > 0 ? value[0] : null;
}

function onlyDigits(value) {
  return String(value || '').replace(/\D/g, '');
}

function nowChileSqlString() {
  const d = new Date();

  const parts = new Intl.DateTimeFormat('sv-SE', {
    timeZone: 'America/Santiago',
    year: 'numeric',
    month: '2-digit',
    day: '2-digit',
    hour: '2-digit',
    minute: '2-digit',
    second: '2-digit',
    hour12: false
  }).formatToParts(d);

  const get = (type) => parts.find(p => p.type === type)?.value;

  return `${get('year')}-${get('month')}-${get('day')} ${get('hour')}:${get('minute')}:${get('second')}`;
}

function metaTimestampToSqlString(timestamp) {
  if (!timestamp) return nowChileSqlString();

  const n = Number(timestamp);
  if (!Number.isFinite(n)) return nowChileSqlString();

  const d = new Date(n * 1000);

  const parts = new Intl.DateTimeFormat('sv-SE', {
    timeZone: 'America/Santiago',
    year: 'numeric',
    month: '2-digit',
    day: '2-digit',
    hour: '2-digit',
    minute: '2-digit',
    second: '2-digit',
    hour12: false
  }).formatToParts(d);

  const get = (type) => parts.find(p => p.type === type)?.value;

  return `${get('year')}-${get('month')}-${get('day')} ${get('hour')}:${get('minute')}:${get('second')}`;
}

function extractMessageText(message) {
  if (!message) return null;

  const type = message.type;

  if (type === 'text') {
    return message.text?.body || null;
  }

  if (type === 'button') {
    return message.button?.text || message.button?.payload || null;
  }

  if (type === 'interactive') {
    return (
      message.interactive?.button_reply?.title ||
      message.interactive?.button_reply?.id ||
      message.interactive?.list_reply?.title ||
      message.interactive?.list_reply?.id ||
      null
    );
  }

  if (type === 'image') {
    return message.image?.caption || null;
  }

  if (type === 'document') {
    return message.document?.caption || message.document?.filename || null;
  }

  if (type === 'video') {
    return message.video?.caption || null;
  }

  if (type === 'audio' || type === 'voice') {
    return '[audio]';
  }

  if (type === 'sticker') {
    return null;
  }

  return null;
}

// -----------------------------
// Detect n8n wrapper / direct Meta payload
// -----------------------------
const metaPayload =
  raw.body && raw.body.entry
    ? raw.body
    : raw.entry
      ? raw
      : raw.body && raw.body.object === 'whatsapp_business_account'
        ? raw.body
        : raw;

const entry = firstArrayItem(metaPayload.entry) || {};
const change = firstArrayItem(entry.changes) || {};
const value = change.value || {};

const metadata = value.metadata || {};
const messages = Array.isArray(value.messages) ? value.messages : [];
const statuses = Array.isArray(value.statuses) ? value.statuses : [];
const contacts = Array.isArray(value.contacts) ? value.contacts : [];

const message = firstArrayItem(messages);
const status = firstArrayItem(statuses);
const contact = firstArrayItem(contacts);

const hasMessage = !!message;
const hasStatus = !!status;

// Regla crítica:
// Si Meta manda messages y statuses juntos, gana message.
// No dejar que status pise un inbound válido.
let event_type = 'unknown';

if (hasMessage) {
  event_type = 'message';
} else if (hasStatus) {
  event_type = 'status';
}

// -----------------------------
// Normalized fields
// -----------------------------
let wa_id = null;
let phone_normalized = null;
let provider_message_id = null;
let message_type = null;
let message_text = null;
let context_message_id = null;
let status_value = null;
let status_timestamp = null;
let occurred_at = nowChileSqlString();

const phone_number_id = metadata.phone_number_id || null;
const display_phone_number = metadata.display_phone_number || null;

const contact_name =
  contact?.profile?.name ||
  raw.contact_name ||
  raw.body?.contact_name ||
  null;

if (event_type === 'message' && message) {
  wa_id = message.from || contact?.wa_id || null;
  phone_normalized = onlyDigits(wa_id);

  provider_message_id = message.id || null;
  message_type = message.type || null;
  message_text = extractMessageText(message);
  context_message_id = message.context?.id || null;

  occurred_at = metaTimestampToSqlString(message.timestamp);
}

if (event_type === 'status' && status) {
  wa_id = status.recipient_id || null;
  phone_normalized = onlyDigits(wa_id);

  provider_message_id = status.id || null;
  status_value = status.status || null;
  status_timestamp = status.timestamp || null;

  occurred_at = metaTimestampToSqlString(status.timestamp);
}

// -----------------------------
// Output contract
// -----------------------------
// IMPORTANTE:
// Este output conserva campos legacy que usan los nodos siguientes:
// - Code - Normalize WhatsApp Message espera messages/contacts/raw_payload
// - Code - Normalize WhatsApp Status espera statuses/metadata/raw_payload
// -----------------------------
return [
  {
    json: {
      // Legacy downstream contract
      raw_payload: metaPayload,
      metadata,
      messages,
      statuses,
      contacts,
      phone_number_id,
      display_phone_number,

      // Normalized fields
      raw,
      event_type,
      channel: 'whatsapp',
      platform: 'meta',

      wa_id,
      phone_normalized,
      contact_name,

      message_type,
      message_text,
      provider_message_id,
      context_message_id,

      status: status_value,
      status_timestamp,
      status_payload: status || null,

      has_message: hasMessage,
      has_status: hasStatus,
      parse_rule: hasMessage && hasStatus
        ? 'message_priority_over_status'
        : 'single_event_type',

      received_at: occurred_at,
      parsed_at: nowChileSqlString(),

      parser_version: '0.2.2',
      parser_source:
        raw.body && raw.body.entry
          ? 'n8n_webhook_body'
          : raw.entry
            ? 'direct_meta_payload'
            : 'fallback'
    }
  }
];

const data = $json;

const message = data.messages?.[0] || {};
const contact = data.contacts?.[0] || {};
const rawPayload = data.raw_payload || {};

function cleanText(value) {
  if (value === null || value === undefined) return "";
  return String(value).trim();
}

function normalizeChilePhone(value) {
  let phone = cleanText(value).replace(/\D/g, "");

  if (!phone) return "";

  // Si viene como 9XXXXXXXX
  if (/^9\d{8}$/.test(phone)) {
    return `56${phone}`;
  }

  // Si viene como 09XXXXXXXX
  if (/^09\d{8}$/.test(phone)) {
    return `56${phone.slice(1)}`;
  }

  // Si viene como 569XXXXXXXX
  if (/^569\d{8}$/.test(phone)) {
    return phone;
  }

  // Si viene con 56 pero sin 9 móvil
  if (/^56\d{9}$/.test(phone)) {
    return phone;
  }

  return phone;
}

function getMessageText(msg) {
  if (msg.type === "text") {
    return msg.text?.body || "";
  }

  if (msg.type === "button") {
    return msg.button?.text || msg.button?.payload || "";
  }

  if (msg.type === "interactive") {
    return (
      msg.interactive?.button_reply?.title ||
      msg.interactive?.button_reply?.id ||
      msg.interactive?.list_reply?.title ||
      msg.interactive?.list_reply?.id ||
      ""
    );
  }

  if (msg.type === "image") {
    return msg.image?.caption || "";
  }

  if (msg.type === "document") {
    return msg.document?.caption || msg.document?.filename || "";
  }

  if (msg.type === "audio") {
    return "[audio]";
  }

  if (msg.type === "video") {
    return msg.video?.caption || "[video]";
  }

  return "";
}

const waId = cleanText(contact.wa_id || message.from);
const phoneNormalized = normalizeChilePhone(waId);
const messageType = cleanText(message.type || "unknown");
const messageText = cleanText(getMessageText(message));

const contextMessageId = cleanText(message.context?.id || "");

const normalized = {
  provider_message_id: cleanText(message.id),
  context_message_id: contextMessageId || null,

  wa_id: waId,
  phone_normalized: phoneNormalized,

  phone_number_id: cleanText(data.phone_number_id),
  display_phone_number: cleanText(data.display_phone_number),

  contact_name: cleanText(contact.profile?.name),

  message_type: messageType,
  message_text: messageText,

  received_at_unix: message.timestamp ? Number(message.timestamp) : null,

  // Todavía no resuelto
  customer_id: null,
  case_id: null,
  service_code: null,
  source_table: null,
  source_id: null,

  raw_payload: rawPayload
};

return [{ json: normalized }];

const msg = $json;

function sqlString(value) {
  if (value === null || value === undefined || value === "") return "NULL";
  return `'${String(value).replace(/\\/g, "\\\\").replace(/'/g, "''")}'`;
}

function sqlNumber(value) {
  if (value === null || value === undefined || value === "") return "NULL";
  const n = Number(value);
  if (Number.isNaN(n)) return "NULL";
  return String(n);
}

const rawPayload = JSON.stringify(msg.raw_payload || {});

const receivedAt = msg.received_at_unix
  ? `CONVERT_TZ(FROM_UNIXTIME(${sqlNumber(msg.received_at_unix)}), '+00:00', '-04:00')`
  : `CONVERT_TZ(UTC_TIMESTAMP(), '+00:00', '-04:00')`;

const query = `
INSERT INTO n8n_wa_inbound_messages (
  provider_message_id,
  context_message_id,
  wa_id,
  phone_number_id,
  message_type,
  message_text,
  processing_status,
  requires_human,
  received_at,
  created_at,
  raw_payload
)
VALUES (
  ${sqlString(msg.provider_message_id)},
  ${sqlString(msg.context_message_id)},
  ${sqlString(msg.wa_id)},
  ${sqlString(msg.phone_number_id)},
  ${sqlString(msg.message_type)},
  ${sqlString(msg.message_text)},
  'received',
  0,
  ${receivedAt},
  CONVERT_TZ(UTC_TIMESTAMP(), '+00:00', '-04:00'),
  ${sqlString(rawPayload)}
);
`;

return [
  {
    json: {
      ...msg,
      phone_normalized: msg.phone_normalized || msg.wa_id,
      insert_inbound_query: query
    }
  }
];

const msg = $("Code - Prepare Insert Inbound").item.json || {};

function clean(value) {
  if (value === null || value === undefined) return "";
  return String(value).trim();
}

const waId = clean(msg.wa_id || msg.phone_normalized);
const phoneNormalized = clean(msg.phone_normalized || msg.wa_id);
const messageText = clean(msg.message_text);
const messageType = clean(msg.message_type || "text");
const providerMessageId = clean(msg.provider_message_id);
const contextMessageId = clean(msg.context_message_id);
const phoneNumberId = clean(msg.phone_number_id);
const displayPhoneNumber = clean(msg.display_phone_number);
const contactName = clean(msg.contact_name);

const receivedAt =
  clean(msg.received_at) ||
  clean(msg.parsed_at) ||
  null;

const contextInput = {
  input_event: {
    event_type: "whatsapp_message",
    channel: "whatsapp",
    platform: "meta",

    wa_id: waId,
    phone_normalized: phoneNormalized,
    phone_number_id: phoneNumberId,
    display_phone_number: displayPhoneNumber,

    contact_name: contactName,

    message_text: messageText,
    message_type: messageType,
    provider_message_id: providerMessageId,
    context_message_id: contextMessageId || null,

    received_at: receivedAt
  },

  customer_context: {},
  case_context: {},
  conversation_context: {},
  business_context: {},

  raw: {
    phone_number_id: phoneNumberId,
    display_phone_number: displayPhoneNumber,
    contact_name: contactName,
    source_node: "Code - Build Context Resolver Input",
    original_message: msg
  }
};

return [{ json: contextInput }];

const s = $json || {};

function sqlString(value) {
  if (value === null || value === undefined || value === "") return "NULL";
  return `'${String(value).replace(/\\/g, "\\\\").replace(/'/g, "''")}'`;
}

function sqlNumber(value) {
  const n = Number(value);
  if (!Number.isFinite(n)) return "NULL";
  return String(n);
}

const status = String(s.message_status || "").trim().toLowerCase();
const providerMessageId = String(s.provider_message_id || "").trim();
const rawPayload = JSON.stringify(s.raw_payload || s || {});

const occurredAt = s.timestamp_unix
  ? `CONVERT_TZ(FROM_UNIXTIME(${sqlNumber(s.timestamp_unix)}), '+00:00', '-04:00')`
  : `CONVERT_TZ(UTC_TIMESTAMP(), '+00:00', '-04:00')`;

let statusColumn = null;

if (status === "sent") statusColumn = "sent_at";
if (status === "delivered") statusColumn = "delivered_at";
if (status === "read") statusColumn = "read_at";
if (status === "failed") statusColumn = "failed_at";

if (!providerMessageId) {
  throw new Error("Missing provider_message_id in WhatsApp status event.");
}

const queryInsertWebhookEventLog = `
INSERT INTO n8n_webhook_event_log (
  source_workflow,
  event_type,
  wa_id,
  message_id,
  payload_json,
  created_at,
  phone_number_id,
  context_message_id,
  service_code,
  case_id,
  processing_status,
  processed_at,
  error_message
)
VALUES (
  'WA_00_Webhook_Master',
  'status',
  ${sqlString(s.wa_id)},
  ${sqlString(providerMessageId)},
  ${sqlString(rawPayload)},
  CONVERT_TZ(UTC_TIMESTAMP(), '+00:00', '-04:00'),
  ${sqlString(s.phone_number_id)},
  NULL,
  NULL,
  NULL,
  'received',
  CONVERT_TZ(UTC_TIMESTAMP(), '+00:00', '-04:00'),
  ${sqlString(s.error_message)}
);
`;

const queryUpdateRelatedOutbound = statusColumn
  ? `
UPDATE n8n_conversation_messages
SET
  message_status = ${sqlString(status)},
  ${statusColumn} = ${occurredAt},
  error_code = COALESCE(${sqlString(s.error_code)}, error_code),
  error_message = COALESCE(${sqlString(s.error_message)}, error_message),
  updated_at = CONVERT_TZ(UTC_TIMESTAMP(), '+00:00', '-04:00')
WHERE provider_message_id = ${sqlString(providerMessageId)}
  AND direction = 'outbound';
`
  : `
UPDATE n8n_conversation_messages
SET
  message_status = ${sqlString(status)},
  error_code = COALESCE(${sqlString(s.error_code)}, error_code),
  error_message = COALESCE(${sqlString(s.error_message)}, error_message),
  updated_at = CONVERT_TZ(UTC_TIMESTAMP(), '+00:00', '-04:00')
WHERE provider_message_id = ${sqlString(providerMessageId)}
  AND direction = 'outbound';
`;

return [
  {
    json: {
      ...s,
      query_insert_webhook_event_log: queryInsertWebhookEventLog,
      query_update_related_outbound: queryUpdateRelatedOutbound
    }
  }
];

const data = $json;

const status = data.statuses?.[0] || {};
const rawPayload = data.raw_payload || {};
const metadata = data.metadata || {};

function cleanText(value) {
  if (value === null || value === undefined) return "";
  return String(value).trim();
}

function firstError(errors) {
  if (!Array.isArray(errors) || errors.length === 0) return {};
  return errors[0] || {};
}

const err = firstError(status.errors);

const normalized = {
  event_type: "whatsapp_status",

  provider_message_id: cleanText(status.id),
  related_provider_message_id: cleanText(status.id),

  wa_id: cleanText(status.recipient_id),
  recipient_id: cleanText(status.recipient_id),

  phone_number_id: cleanText(metadata.phone_number_id || data.phone_number_id),
  display_phone_number: cleanText(metadata.display_phone_number || data.display_phone_number),

  message_status: cleanText(status.status),
  timestamp_unix: status.timestamp ? Number(status.timestamp) : null,

  conversation_id: cleanText(status.conversation?.id),
  conversation_origin_type: cleanText(status.conversation?.origin?.type),

  pricing_model: cleanText(status.pricing?.pricing_model),
  pricing_category: cleanText(status.pricing?.category),
  billable: status.pricing?.billable ?? null,

  error_code: cleanText(err.code),
  error_title: cleanText(err.title),
  error_message: cleanText(err.message || err.error_data?.details),

  raw_payload: rawPayload
};

return [{ json: normalized }];

const event = $json;

function sqlString(value) {
  if (value === null || value === undefined || value === "") return "NULL";
  return `'${String(value).replace(/\\/g, "\\\\").replace(/'/g, "''")}'`;
}

const rawPayload = JSON.stringify(event.raw_payload || event || {});

const phoneNumberId =
  event.phone_number_id ||
  event.metadata?.phone_number_id ||
  event.value?.metadata?.phone_number_id ||
  null;

const query = `
INSERT INTO n8n_webhook_event_log (
  source_workflow,
  event_type,
  wa_id,
  message_id,
  payload_json,
  created_at,
  phone_number_id,
  context_message_id,
  service_code,
  case_id,
  processing_status,
  processed_at,
  error_message
)
VALUES (
  'WA_00_Webhook_Master',
  'unknown',
  NULL,
  NULL,
  ${sqlString(rawPayload)},
  CONVERT_TZ(UTC_TIMESTAMP(), '+00:00', '-04:00'),
  ${sqlString(phoneNumberId)},
  NULL,
  NULL,
  NULL,
  'unclassified',
  NULL,
  'Webhook event could not be classified as message or status.'
);
`;

return [
  {
    json: {
      event_type: "unknown",
      query_unknown_event_log: query,
      raw_payload: event.raw_payload || event
    }
  }
];

const data = $json || {};

function clean(value) {
  if (value === null || value === undefined) return "";
  return String(value).trim();
}

function sqlString(value) {
  if (value === null || value === undefined || value === "") return "NULL";
  return `'${String(value).replace(/\\/g, "\\\\").replace(/'/g, "''")}'`;
}

function sqlNumber(value) {
  if (value === null || value === undefined || value === "") return "NULL";
  const n = Number(value);
  if (!Number.isFinite(n)) return "NULL";
  return String(n);
}

function sqlJson(value) {
  if (value === null || value === undefined) return "NULL";
  return sqlString(JSON.stringify(value));
}

const inputEvent = data.input_event || data;

const waId = clean(
  inputEvent.wa_id ||
  inputEvent.from ||
  inputEvent.phone_normalized ||
  data.wa_id ||
  data.from ||
  data.phone_normalized
);

const phoneNormalized = clean(
  inputEvent.phone_normalized ||
  inputEvent.wa_id ||
  data.phone_normalized ||
  data.wa_id ||
  waId
);

const providerMessageId = clean(
  inputEvent.provider_message_id ||
  inputEvent.message_id ||
  inputEvent.id ||
  data.provider_message_id ||
  data.message_id ||
  data.id
);

const contextMessageId = clean(
  inputEvent.context_message_id ||
  inputEvent.context?.id ||
  data.context_message_id ||
  data.context?.id
);

const messageType = clean(
  inputEvent.message_type ||
  inputEvent.type ||
  data.message_type ||
  data.type ||
  "text"
);

const messageText = clean(
  inputEvent.message_text ||
  inputEvent.text ||
  inputEvent.text_body ||
  inputEvent.button_text ||
  inputEvent.interactive_text ||
  data.message_text ||
  data.text ||
  data.text_body ||
  data.button_text ||
  data.interactive_text
);

const contactName = clean(
  inputEvent.contact_name ||
  inputEvent.profile_name ||
  data.contact_name ||
  data.profile_name
);

const phoneNumberId = clean(
  inputEvent.phone_number_id ||
  data.phone_number_id
);

const rawPayload = data.raw_payload || data.raw || data;

if (!waId) {
  throw new Error("Cannot insert inbound conversation message: missing wa_id");
}

if (!providerMessageId) {
  throw new Error("Cannot insert inbound conversation message: missing provider_message_id");
}

const query = `
INSERT INTO n8n_conversation_messages (
  customer_master_id,
  wa_id,
  contact_name,
  phone_number_id,
  channel,
  platform,
  direction,
  provider_message_id,
  context_message_id,
  related_provider_message_id,
  message_type,
  message_text,
  template_name,
  template_language,
  service_code,
  campaign_code,
  source_table,
  source_id,
  id_order,
  id_customer,
  invoice_number,
  intent,
  department,
  final_action,
  message_status,
  received_at,
  raw_payload,
  created_at,
  updated_at
)
VALUES (
  NULL,
  ${sqlString(waId)},
  ${sqlString(contactName)},
  ${sqlString(phoneNumberId)},
  'whatsapp',
  'meta',
  'inbound',
  ${sqlString(providerMessageId)},
  ${sqlString(contextMessageId)},
  NULL,
  ${sqlString(messageType)},
  ${sqlString(messageText)},
  NULL,
  NULL,
  NULL,
  NULL,
  NULL,
  NULL,
  NULL,
  NULL,
  NULL,
  NULL,
  NULL,
  NULL,
  'received',
  CONVERT_TZ(UTC_TIMESTAMP(), '+00:00', '-04:00'),
  ${sqlJson(rawPayload)},
  CONVERT_TZ(UTC_TIMESTAMP(), '+00:00', '-04:00'),
  CONVERT_TZ(UTC_TIMESTAMP(), '+00:00', '-04:00')
)
ON DUPLICATE KEY UPDATE
  context_message_id = COALESCE(VALUES(context_message_id), context_message_id),
  message_text = COALESCE(VALUES(message_text), message_text),
  raw_payload = VALUES(raw_payload),
  updated_at = CONVERT_TZ(UTC_TIMESTAMP(), '+00:00', '-04:00');
`;

return [
  {
    json: {
      ...data,
      input_event: {
        ...(data.input_event || {}),
        wa_id: waId,
        phone_normalized: phoneNormalized,
        provider_message_id: providerMessageId,
        context_message_id: contextMessageId,
        message_type: messageType,
        message_text: messageText,
        contact_name: contactName,
        phone_number_id: phoneNumberId
      },
      inbound_message_insert_query: query
    }
  }
];

// Loop over input items and add a new field called 'myNewField' to the JSON of each one
for (const item of $input.all()) {
  item.json.myNewField = 1;
}

return $input.all();

const data = $("Code - Prepare Insert Inbound").item.json || {};

delete data.insert_inbound_query;
delete data.inbound_insert_query;
delete data.raw_inbound_insert_query;

return [{ json: data }];

const data = $json || {};

function clean(value) {
  if (value === null || value === undefined) return "";
  return String(value).trim();
}

function sqlString(value) {
  if (value === null || value === undefined || value === "") return "NULL";
  return `'${String(value).replace(/\\/g, "\\\\").replace(/'/g, "''")}'`;
}

function sqlJson(value) {
  if (value === null || value === undefined) return "NULL";
  return sqlString(JSON.stringify(value));
}

const inputEvent = data.input_event || data;

const waId = clean(
  inputEvent.wa_id ||
  inputEvent.from ||
  inputEvent.phone_normalized ||
  data.wa_id ||
  data.from ||
  data.phone_normalized
);

const phoneNormalized = clean(
  inputEvent.phone_normalized ||
  inputEvent.wa_id ||
  data.phone_normalized ||
  data.wa_id ||
  waId
);

const providerMessageId = clean(
  inputEvent.provider_message_id ||
  inputEvent.message_id ||
  inputEvent.id ||
  data.provider_message_id ||
  data.message_id ||
  data.id
