// -----------------------------
// Helpers
// -----------------------------
function clean(value) {
  if (value === null || value === undefined) return "";
  return String(value).trim();
}

function asObject(value) {
  return value && typeof value === "object" && !Array.isArray(value) ? value : {};
}

function pickFirst(...values) {
  for (const value of values) {
    const v = clean(value);
    if (v) return v;
  }
  return "";
}

function pickFirstRaw(...values) {
  for (const value of values) {
    if (value !== null && value !== undefined && value !== "") return value;
  }
  return null;
}

function normalizePhone(value) {
  return clean(value).replace(/\D/g, "");
}

function get(obj, path, fallback = null) {
  if (!obj) return fallback;

  const parts = path.split(".");
  let acc = obj;

  for (const key of parts) {
    if (acc && Object.prototype.hasOwnProperty.call(acc, key)) {
      acc = acc[key];
    } else {
      return fallback;
    }
  }

  return acc === undefined ? fallback : acc;
}

function getNodeJson(nodeName) {
  try {
    return $(nodeName).item.json || {};
  } catch (e) {
    return {};
  }
}

function nowChileSqlString() {
  const d = new Date();

  const parts = new Intl.DateTimeFormat("sv-SE", {
    timeZone: "America/Santiago",
    year: "numeric",
    month: "2-digit",
    day: "2-digit",
    hour: "2-digit",
    minute: "2-digit",
    second: "2-digit",
    hour12: false
  }).formatToParts(d);

  const part = (type) => parts.find(p => p.type === type)?.value;

  return `${part("year")}-${part("month")}-${part("day")} ${part("hour")}:${part("minute")}:${part("second")}`;
}

function chileSqlFromUnix(unixValue) {
  const n = Number(unixValue);
  if (!Number.isFinite(n)) return "";

  const d = new Date(n * 1000);

  const parts = new Intl.DateTimeFormat("sv-SE", {
    timeZone: "America/Santiago",
    year: "numeric",
    month: "2-digit",
    day: "2-digit",
    hour: "2-digit",
    minute: "2-digit",
    second: "2-digit",
    hour12: false
  }).formatToParts(d);

  const part = (type) => parts.find(p => p.type === type)?.value;

  return `${part("year")}-${part("month")}-${part("day")} ${part("hour")}:${part("minute")}:${part("second")}`;
}

function normalizeTopic(value) {
  const v = clean(value)
    .toLowerCase()
    .normalize("NFD")
    .replace(/[\u0300-\u036f]/g, "");

  const map = {
    reclamo: "reclamo",
    garantia: "garantia",
    despacho: "despacho",
    envio: "despacho",
    armado: "armado",
    mantencion: "mantencion",
    mantenimiento: "mantencion",
    pedido: "pedido",
    compra: "asesoria_compra",
    asesoria_compra: "asesoria_compra",
    consulta_general: "consulta_general"
  };

  return map[v] || "consulta_general";
}

function buildThreadKey(receivedAt) {
  let d = receivedAt ? new Date(receivedAt) : new Date();

  if (Number.isNaN(d.getTime())) {
    d = new Date();
  }

  const yyyy = d.getFullYear();
  const mm = String(d.getMonth() + 1).padStart(2, "0");
  const dd = String(d.getDate()).padStart(2, "0");

  return `thread:${yyyy}${mm}${dd}`;
}

